#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100005

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[MAX];
        scanf("%s", s);
        int n = strlen(s);
        int freq[26] = {0};
        for (int i = 0; i < n; i++) {
            freq[s[i] - 'a']++;
        }
        int max_freq = 0;
        for (int i = 0; i < 26; i++) {
            max_freq = (max_freq > freq[i]) ? max_freq : freq[i];
        }
        if (max_freq > (n + 1) / 2) {
            printf("-1\n");
        } else {
            char result[MAX] = {0};
            int index = 0;
            while (index < n) {
                for (int i = 0; i < 26; i++) {
                    if (freq[i] > 0) {
                        result[index] = 'a' + i;
                        freq[i]--;
                        index++;
                        if (index < n) {
                            for (int j = 0; j < 26; j++) {
                                if (freq[j] > 0 && j != i) {
                                    result[index] = 'a' + j;
                                    freq[j]--;
                                    index++;
                                    break;
                                }
                            }
                        }
                    }
                }
            }
            printf("%s\n", result);
        }
    }
    return 0;
}

