import java.util.PriorityQueue;
import java.util.Scanner;
import java.util.Comparator;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int n = s.length();
            int[] freq = new int[26];
            for (int i = 0; i < n; i++) {
                freq[s.charAt(i) - 'a']++;
            }
            PriorityQueue<Color> pq = new PriorityQueue<>(new Comparator<Color>() {
                @Override
                public int compare(Color o1, Color o2) {
                    return o1.freq - o2.freq;
                }
            });
            for (int i = 0; i < 26; i++) {
                if (freq[i] > 0) {
                    pq.add(new Color((char) ('a' + i), freq[i]));
                }
            }
            StringBuilder result = new StringBuilder();
            while (!pq.isEmpty()) {
                Color c1 = pq.poll();
                result.append(c1.c);
                c1.freq--;
                if (!pq.isEmpty()) {
                    Color c2 = pq.poll();
                    result.append(c2.c);
                    c2.freq--;
                    if (c1.freq > 0) {
                        pq.add(c1);
                    }
                    if (c2.freq > 0) {
                        pq.add(c2);
                    }
                } else if (c1.freq > 0) {
                    System.out.println(-1);
                    break;
                }
            }
            if (result.length() == n) {
                System.out.println(result);
            }
        }
    }
}

