import sys
from collections import Counter

def solve(s):
    n = len(s)
    freq = Counter(s)
    max_freq = max(freq.values())
    if max_freq > (n + 1) // 2:
        return -1
    result = []
    while freq:
        c1 = max(freq, key=freq.get)
        result.append(c1)
        freq[c1] -= 1
        if freq[c1] == 0:
            del freq[c1]
        if freq:
            c2 = max(freq, key=freq.get)
            result.append(c2)
            freq[c2] -= 1
            if freq[c2] == 0:
                del freq[c2]
    return ''.join(result)

T = int(input())
for _ in range(T):
    s = input()
    print(solve(s))

