function solve(s) {
    const n = s.length;
    const freq = {};
    for (let i = 0; i < n; i++) {
        if (!freq[s[i]]) {
            freq[s[i]] = 0;
        }
        freq[s[i]]++;
    }
    let maxFreq = 0;
    for (let c in freq) {
        maxFreq = Math.max(maxFreq, freq[c]);
    }
    if (maxFreq > (n + 1) / 2) {
        return -1;
    }
    const result = [];
    while (Object.keys(freq).length > 0) {
        let c1 = null;
        let max = 0;
        for (let c in freq) {
            if (freq[c] > max) {
                max = freq[c];
                c1 = c;
            }
        }
        result.push(c1);
        freq[c1]--;
        if (freq[c1] === 0) {
            delete freq[c1];
        }
        if (Object.keys(freq).length > 0) {
            let c2 = null;
            let max2 = 0;
            for (let c in freq) {
                if (freq[c] > max2) {
                    max2 = freq[c];
                    c2 = c;
                }
            }
            result.push(c2);
            freq[c2]--;
            if (freq[c2] === 0) {
                delete freq[c2];
            }
        }
    }
    return result.join('');
}

